sum = sum + number;                         //Line 7
counter++;                                   //Line 8
}
cout  << "Line 9: The sum of the " << limit
<< " numbers = " << sum <<  endl ;           //Line 9
if (counter != 0)                               //Line 10
cout  << "Line 11: The average = "
<< sum / counter <<  endl ;              //Line 11
