//guessed by the user
bool done;   // boolean  variable to control
//the loop
num = (rand() + time(0)) % 100;                 //Line 1
done = false;                                   //Line 2
while (!done)                                    //Line 3
{                                               //Line 4
cout  << "Enter an integer greater"       << " than or equal to 0 and "<< "less than 100: ";                  //Line 5
cin  >> guess;                               //Line 6
cout  <<  endl ;                               //Line 7
if (guess == num)                           //Line 8
{                                           //Line 9
cout  << "You guessed the correct "
<< "number." <<  endl ;              //Line 10
done = true;                            //Line 11
}                                            //Line 12
else                                        //Line 13
